483	// CycleTime computes lifecycle timing facts.
484	func (s *Service) CycleTime(query Query) (CycleTimeReport, error) {
485		beads, sessions, sessionByID, _, err := s.loadInputs()
486		if err != nil {
487			return CycleTimeReport{}, err
488		}
489		_ = sessions
490	
491		rows := make([]CycleTimeRow, 0, len(beads))
492		for _, b := range beads {
493			row := buildCycleTimeRow(s.WorkingDir, b, sessionByID)
494			if query.HasSince && row.FirstClosedAt != nil && row.FirstClosedAt.Before(query.Since) {
495				continue
496			}
497			rows = append(rows, row)
498		}
499		sort.Slice(rows, func(i, j int) bool {
500			if rows[i].FirstClosedAt == nil && rows[j].FirstClosedAt == nil {
501				return rows[i].BeadID < rows[j].BeadID
502			}
503			if rows[i].FirstClosedAt == nil {
504				return false
505			}
506			if rows[j].FirstClosedAt == nil {
507				return true
508			}
509			if !rows[i].FirstClosedAt.Equal(*rows[j].FirstClosedAt) {
510				return rows[i].FirstClosedAt.Before(*rows[j].FirstClosedAt)
511			}
512			return rows[i].BeadID < rows[j].BeadID
513		})
514	
515		report := CycleTimeReport{
516			Scope:  "all",
517			Window: windowForQuery(query),
518			Beads:  rows,
519		}
520		for _, row := range rows {
521			if row.CycleState == stateKnown && row.CycleTimeMS != nil {
522				report.Summary.KnownCount++
523				if report.Summary.AverageMS == nil {
524					report.Summary.AverageMS = int64Ptr(0)
525					report.Summary.MinMS = int64Ptr(*row.CycleTimeMS)
526					report.Summary.MaxMS = int64Ptr(*row.CycleTimeMS)
527				}
528				*report.Summary.AverageMS += *row.CycleTimeMS
529				if row.CycleTimeMS != nil {
530					if *row.CycleTimeMS < *report.Summary.MinMS {
531						*report.Summary.MinMS = *row.CycleTimeMS
532					}
533					if *row.CycleTimeMS > *report.Summary.MaxMS {
534						*report.Summary.MaxMS = *row.CycleTimeMS
535					}
536				}
537			} else {
538				report.Summary.UnknownCount++
539			}
540		}
541		if report.Summary.KnownCount > 0 && report.Summary.AverageMS != nil {
542			avg := *report.Summary.AverageMS / int64(report.Summary.KnownCount)
543			report.Summary.AverageMS = &avg
544		}
545		return report, nil
546	}
