548	// Rework computes reopen and revision facts.
549	func (s *Service) Rework(query Query) (ReworkReport, error) {
550		beads, sessions, sessionByID, _, err := s.loadInputs()
551		if err != nil {
552			return ReworkReport{}, err
553		}
554		_ = sessions
555	
556		rows := make([]ReworkRow, 0, len(beads))
557		for _, b := range beads {
558			row := buildReworkRow(s.WorkingDir, b, sessionByID)
559			if query.HasSince && row.FirstClosedAt != nil && row.FirstClosedAt.Before(query.Since) {
560				continue
561			}
562			rows = append(rows, row)
563		}
564		sort.Slice(rows, func(i, j int) bool {
565			if rows[i].FirstClosedAt == nil && rows[j].FirstClosedAt == nil {
566				return rows[i].BeadID < rows[j].BeadID
567			}
568			if rows[i].FirstClosedAt == nil {
569				return false
570			}
571			if rows[j].FirstClosedAt == nil {
572				return true
573			}
574			if !rows[i].FirstClosedAt.Equal(*rows[j].FirstClosedAt) {
575				return rows[i].FirstClosedAt.Before(*rows[j].FirstClosedAt)
576			}
577			return rows[i].BeadID < rows[j].BeadID
578		})
579	
580		report := ReworkReport{
581			Scope:  "all",
582			Window: windowForQuery(query),
583			Beads:  rows,
584		}
585	
586		for _, row := range rows {
587			if row.ReworkState != stateKnown {
588				report.Summary.UnknownCount++
589				continue
590			}
591			report.Summary.KnownClosed++
592			if row.Reopened {
593				report.Summary.KnownReopened++
594			}
595			if row.RevisionCount != nil {
596				report.Summary.RevisionCount += *row.RevisionCount
597			}
598		}
599		if report.Summary.KnownClosed > 0 {
600			report.Summary.ReopenRate = float64(report.Summary.KnownReopened) / float64(report.Summary.KnownClosed)
601		}
602		return report, nil
603	}
