627	func beadsVisibleInSummaryWindow(beads []bead.Bead, query Query, costReport CostReport, cycleReport CycleTimeReport, reworkReport ReworkReport) ([]bead.Bead, map[string]struct{}) {
628		if !query.HasSince || query.Since.IsZero() {
629			visibleIDs := make(map[string]struct{}, len(beads))
630			for _, b := range beads {
631				visibleIDs[b.ID] = struct{}{}
