710	func readSessions(path string) ([]agent.SessionEntry, map[string]bool, error) {
711		if filepath.Base(path) == "sessions.jsonl" {
712			logDir := filepath.Dir(path)
713			indexEntries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
714			if err != nil {
715				return nil, nil, err
716			}
717			sessions := make([]agent.SessionEntry, 0, len(indexEntries))
718			costPresent := make(map[string]bool, len(indexEntries))
719			for _, idx := range indexEntries {
720				entry := agent.SessionIndexEntryToLegacy(idx)
721				sessions = append(sessions, entry)
722				costPresent[entry.ID] = idx.CostPresent || idx.CostUSD != 0
723			}
724			return sessions, costPresent, nil
725		}
726		records, err := readJSONLRecords[sessionLoadRecord](path)
727		if err != nil {
728			return nil, nil, err
729		}
730	
731		sessions := make([]agent.SessionEntry, 0, len(records))
732		costPresent := make(map[string]bool, len(records))
733		for _, rec := range records {
734			sessions = append(sessions, rec.Entry)
735			costPresent[rec.Entry.ID] = rec.CostUSDPresent
736		}
737		return sessions, costPresent, nil
738	}
