740	func readJSONLRecords[T any](path string) ([]T, error) {
741		f, err := os.Open(path)
742		if os.IsNotExist(err) {
743			return nil, nil
744		}
745		if err != nil {
746			return nil, err
747		}
748		defer f.Close()
749	
750		scanner := bufio.NewScanner(f)
751		// 16MB max line — matches bead/session scanners; process-metrics rows are
752		// small but consistency avoids surprise truncation if a writer ever grows.
753		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
754		var out []T
755		for scanner.Scan() {
756			line := strings.TrimSpace(scanner.Text())
757			if line == "" {
758				continue
759			}
760			var rec T
761			if err := json.Unmarshal([]byte(line), &rec); err != nil {
762				continue
763			}
764			out = append(out, rec)
765		}
766		if err := scanner.Err(); err != nil {
767			return nil, err
768		}
769		return out, nil
770	}
