793	func buildBeadCostRow(b bead.Bead, sessions []agent.SessionEntry, sessionByID map[string]agent.SessionEntry, sessionCostPresent map[string]bool, query Query) BeadCostRow {
794		matches := matchedSessionsForBead(b, sessions, sessionByID)
795		if query.HasSince {
796			filtered := matches[:0]
797			for _, sess := range matches {
798				if sess.Timestamp.Before(query.Since) {
799					continue
800				}
801				filtered = append(filtered, sess)
802			}
803			matches = filtered
804		}
805	
806		row := BeadCostRow{
807			BeadID:     b.ID,
808			Title:      b.Title,
809			SpecID:     extraString(b, "spec-id", "spec_id"),
810			Status:     b.Status,
811			SessionIDs: make([]string, 0, len(matches)),
812			Provenance: make([]SourceRef, 0, len(matches)),
813		}
814	
815		var costTotal float64
816		var knownCount, estimatedCount, unknownCount int
817		for _, sess := range matches {
818			explicitCost := sessionCostPresent[sess.ID]
819			row.SessionIDs = append(row.SessionIDs, sess.ID)
820			row.InputTokens += sessionInputTokens(sess)
821			row.OutputTokens += sessionOutputTokens(sess)
822			row.TotalTokens += sessionTotalTokens(sess)
823	
824			if cost := sessionDerivedCost(sess, explicitCost); cost != nil {
825				costTotal += *cost
826				if sessionCostState(sess, explicitCost) == stateKnown {
827					knownCount++
828				} else {
829					estimatedCount++
830				}
831			} else {
832				unknownCount++
833			}
834	
835			row.Provenance = append(row.Provenance, sourceRefForSession(b.ID, sess))
836		}
837	
838		switch {
839		case len(matches) == 0:
840			row.CostState = stateUnknown
841		case unknownCount > 0 && knownCount == 0 && estimatedCount == 0:
842			row.CostState = stateUnknown
843		case estimatedCount > 0:
844			row.CostState = stateEstimated
845		default:
846			row.CostState = stateKnown
847		}
848		if row.CostState != stateUnknown {
849			row.CostUSD = float64Ptr(costTotal)
850		}
851		row.UnknownSessions = unknownCount
852		return row
853	}
