913	func buildCycleTimeRow(workingDir string, b bead.Bead, sessionByID map[string]agent.SessionEntry) CycleTimeRow {
914		row := CycleTimeRow{
915			BeadID:     b.ID,
916			Title:      b.Title,
917			SpecID:     extraString(b, "spec-id", "spec_id"),
918			Status:     b.Status,
919			CreatedAt:  b.CreatedAt.UTC(),
920			CycleState: stateUnknown,
921		}
922	
923		events := beadEvents(b)
924		transitions := recognizedTransitions(events)
925		sort.Slice(transitions, func(i, j int) bool {
926			return transitions[i].At.Before(transitions[j].At)
927		})
928	
929		closeAt, provenance := firstCloseEvidence(workingDir, b, transitions, sessionByID)
930		if closeAt != nil {
931			row.FirstClosedAt = closeAt
932			row.CycleTimeMS = int64Ptr(closeAt.Sub(b.CreatedAt).Milliseconds())
933			row.CycleState = stateKnown
934			row.Provenance = append(row.Provenance, provenance...)
935		}
936	
937		if len(transitions) == 0 {
938			return row
939		}
940	
941		row.Provenance = append(row.Provenance, provenanceForEvents(b.ID, events)...)
942	
943		var lastStatus string
944		var lastAt time.Time
945		var firstClosedSeen bool
946		var reopenCount int
947		var revisionCount int
948		var timing lifecycleTimingBuckets
949		for i, tr := range transitions {
950			if i == 0 {
951				lastStatus = bead.StatusOpen
952				lastAt = b.CreatedAt.UTC()
953			}
954			if tr.At.Before(lastAt) {
955				continue
956			}
957			delta := tr.At.Sub(lastAt).Milliseconds()
958			timing.add(lastStatus, delta)
959			if tr.Status == bead.StatusClosed && !firstClosedSeen {
960				firstClosedSeen = true
961				if row.FirstClosedAt == nil {
962					ts := tr.At
963					row.FirstClosedAt = &ts
964					row.CycleTimeMS = int64Ptr(ts.Sub(b.CreatedAt).Milliseconds())
965					row.CycleState = stateKnown
966				}
967			}
968			if firstClosedSeen {
969				if tr.Status == bead.StatusClosed {
970					// Status closed is part of the close window; do not count it as rework.
971				} else {
972					revisionCount++
973					if lastStatus == bead.StatusClosed && (tr.Status == bead.StatusOpen || tr.Status == bead.StatusInProgress) {
974						reopenCount++
975					}
976				}
977			}
978			lastStatus = tr.Status
979			lastAt = tr.At
980		}
981	
982		end := b.UpdatedAt.UTC()
983		if end.Before(lastAt) {
984			end = lastAt
985		}
986		if !end.IsZero() {
987			delta := end.Sub(lastAt).Milliseconds()
988			timing.add(lastStatus, delta)
989		}
990	
991		if timing.proposedMS > 0 {
992			row.TimeInProposedMS = int64Ptr(timing.proposedMS)
993		}
994		if timing.openMS > 0 {
995			row.TimeInOpenMS = int64Ptr(timing.openMS)
996		}
997		if timing.inProgressMS > 0 {
998			row.TimeInProgressMS = int64Ptr(timing.inProgressMS)
999		}
1000		if timing.blockedMS > 0 {
1001			row.TimeInBlockedMS = int64Ptr(timing.blockedMS)
1002		}
1003		if timing.closedMS > 0 {
1004			row.TimeInClosedMS = int64Ptr(timing.closedMS)
1005		}
1006		if timing.cancelledMS > 0 {
1007			row.TimeInCancelledMS = int64Ptr(timing.cancelledMS)
1008		}
1009		if firstClosedSeen {
1010			row.ReopenCount = intPtr(reopenCount)
1011			row.RevisionCount = intPtr(revisionCount)
1012		}
1013	
1014		if firstClosedSeen {
1015			lastClose := row.FirstClosedAt
1016			for _, tr := range transitions {
1017				if tr.Status == bead.StatusClosed {
1018					ts := tr.At
1019					lastClose = &ts
1020				}
1021			}
1022			row.LastClosedAt = lastClose
1023		}
1024		return row
1025	}
