1105	func matchedSessionsForBead(b bead.Bead, sessions []agent.SessionEntry, sessionByID map[string]agent.SessionEntry) []agent.SessionEntry {
1106		beadID := b.ID
1107		seen := make(map[string]struct{})
1108		out := make([]agent.SessionEntry, 0)
1109	
1110		for _, sess := range sessions {
1111			if sessionBeadID(sess) == beadID {
1112				if _, ok := seen[sess.ID]; !ok {
1113					out = append(out, sess)
1114					seen[sess.ID] = struct{}{}
1115				}
1116			}
1117		}
1118	
1119		if sessionID := extraString(b, "session_id", "session-id"); sessionID != "" {
1120			if sess, ok := sessionByID[sessionID]; ok {
1121				if _, exists := seen[sess.ID]; !exists {
1122					out = append(out, sess)
1123					seen[sess.ID] = struct{}{}
1124				}
1125			}
1126		}
1127	
1128		sort.Slice(out, func(i, j int) bool {
1129			if out[i].Timestamp.Equal(out[j].Timestamp) {
1130				return out[i].ID < out[j].ID
1131			}
1132			return out[i].Timestamp.Before(out[j].Timestamp)
1133		})
1134		return out
1135	}
