399	func resolveRateLimitRetryConfig(opts AttemptOpts) RateLimitRetryConfig {
400		cfg := RateLimitRetryConfig{
401			Budget:     opts.RateLimitBudget,
402			PerWaitCap: opts.RateLimitPerWaitCap,
403			Evaluator:  opts.RateLimitWaitEvaluator,
404			Sleep:      opts.RateLimitSleep,
405			Now:        opts.RateLimitNow,
406			OnRetry:    opts.RateLimitOnRetry,
407		}
408		if cfg.Budget == 0 {
409			cfg.Budget = RateLimitRetryDefaultBudget
410		}
411		if cfg.PerWaitCap == 0 {
412			cfg.PerWaitCap = RateLimitRetryDefaultPerWaitCap
413		}
414		if cfg.Sleep == nil {
415			cfg.Sleep = ctxSleep
416		}
417		if cfg.Now == nil {
418			cfg.Now = time.Now
419		}
420		if cfg.Evaluator == nil {
421			cfg.Evaluator = EvaluateRateLimitWait
422		}
423		return cfg
424	}
425	
426	func ctxSleep(ctx context.Context, d time.Duration) error {
427		if d <= 0 {
428			return nil
429		}
430		t := time.NewTimer(d)
431		defer t.Stop()
432		select {
433		case <-ctx.Done():
434			return ctx.Err()
435		case <-t.C:
436			return nil
437		}
438	}
439	
440	func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
441		if cfg.Budget < 0 || budget < 0 {
442			return RateLimitWaitDecision{ShouldRetry: false}, 0
443		}
444		if !IsRateLimitReport(&report) {
445			return RateLimitWaitDecision{ShouldRetry: false}, 0
446		}
447	
448		retryAfter := ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
449		decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
450		if !decision.ShouldRetry {
451			decision.Reason = RateLimitBudgetExhaustedReason
452		}
453		return decision, retryAfter
454	}
455	
456	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
457		if budget > 0 && elapsed >= budget {
458			return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
459		}
460	
461		var wait time.Duration
462		var source string
463		if retryAfter > 0 {
464			wait = retryAfter
465			source = "retry-after"
466		} else {
467			idx := attempt - 1
468			if idx < 0 {
469				idx = 0
470			}
471			if idx >= len(rateLimitBackoffSchedule) {
472				idx = len(rateLimitBackoffSchedule) - 1
473			}
474			wait = rateLimitBackoffSchedule[idx]
475			source = "exponential-backoff"
476		}
477	
478		if perWaitCap > 0 && wait > perWaitCap {
479			wait = perWaitCap
480		}
481	
482		if budget > 0 && elapsed+wait > budget {
483			remaining := budget - elapsed
484			if remaining <= 0 {
485				return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
486			}
487			wait = remaining
488		}
489	
490		return RateLimitWaitDecision{ShouldRetry: true, Wait: wait, Source: source}
491	}
492	
493	func IsRateLimitReport(report *Report) bool {
494		if report == nil {
495			return false
496		}
497		combined := strings.ToLower(report.Error + "\n" + report.Stderr + "\n" + report.Detail)
498		if combined == "\n\n" {
499			return false
500		}
501		if strings.Contains(combined, "quota exceeded") ||
502			strings.Contains(combined, "insufficient quota") ||
503			strings.Contains(combined, "no viable provider") {
504			return false
505		}
506		if strings.Contains(combined, "rate limit") || strings.Contains(combined, "ratelimit") {
507			return true
508		}
509		return hasIsolated429(combined)
510	}
511	
512	func hasIsolated429(s string) bool {
513		for i := 0; i+3 <= len(s); i++ {
514			if s[i:i+3] != "429" {
515				continue
516			}
517			if i > 0 {
518				c := s[i-1]
519				if c >= '0' && c <= '9' {
520					continue
521				}
522			}
523			if i+3 < len(s) {
524				c := s[i+3]
525				if c >= '0' && c <= '9' {
526					continue
527				}
528			}
529			return true
530		}
531		return false
532	}
533	
534	func ParseRetryAfter(value string, now time.Time) time.Duration {
535		value = strings.TrimSpace(value)
536		if value == "" {
537			return 0
538		}
539		if secs, err := strconv.Atoi(value); err == nil {
540			if secs < 0 {
541				return 0
542			}
543			return time.Duration(secs) * time.Second
544		}
545		if t, err := http.ParseTime(value); err == nil {
546			d := t.Sub(now)
547			if d < 0 {
548				return 0
549			}
550			return d
551		}
552		if d, err := time.ParseDuration(value); err == nil && d >= 0 {
553			return d
554		}
555		return 0
556	}
557	
558	func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
559		if stderr == "" {
560			return 0
561		}
562		lower := strings.ToLower(stderr)
563		for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
564			idx := strings.Index(lower, marker)
565			if idx < 0 {
566				continue
567			}
568			rest := stderr[idx+len(marker):]
569			if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
570				rest = rest[:eol]
571			}
572			rest = strings.TrimSpace(rest)
573			rest = strings.Trim(rest, "\"',")
574			if d := ParseRetryAfter(rest, now); d > 0 {
575				return d
576			}
577		}
578		return 0
579	}
580	
581	func ShouldAttemptConflictRecovery(report Report, projectRoot string) bool {
582		if report.PreserveRef == "" || projectRoot == "" {
583			return false
584		}
585		switch report.Status {
586		case StatusLandConflict:
587			return true
588		case StatusExecutionFailed:
589			return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
590		}
591		return false
592	}
